import api from './api';
export default {
  async getAll() {
    const response = await api.request('list', 'RentalConfiguration', {});
    return response.data || [];
  },
  async create(configuration) {
    const response = await api.request('save', 'RentalConfiguration', configuration);
    return response.data;
  },
  async update(id, configuration) {
    const response = await api.request('update', 'RentalConfiguration', {
      id,
      ...configuration
    });
    return response.data;
  },
  async delete(id) {
    await api.request('delete', 'RentalConfiguration', {
      id
    });
  },
  async updateSortOrders(configurations) {
    const response = await api.request('updateSort', 'RentalConfiguration', {
      configurations
    });
    return response.data;
  }
};
